63	// MarshalXML allows type H to be used with xml.Marshal.
64	func (h H) MarshalXML(e *xml.Encoder, start xml.StartElement) error {
65		start.Name = xml.Name{
66			Space: "",
67			Local: "map",
68		}
69		if err := e.EncodeToken(start); err != nil {
70			return err
71		}
72		for key, value := range h {
73			elem := xml.StartElement{
74				Name: xml.Name{Space: "", Local: key},
75				Attr: []xml.Attr{},
76			}
77			if err := e.EncodeElement(value, elem); err != nil {
78				return err
79			}
80		}
81	
82		return e.EncodeToken(xml.EndElement{Name: start.Name})
83	}
